package com.cybersecuals.gridgarrison.trust.contract;

import org.web3j.protocol.Web3j;
import org.web3j.crypto.Credentials;
import org.web3j.tx.Contract;
import org.web3j.tx.gas.ContractGasProvider;
import org.web3j.protocol.core.RemoteCall;
import org.web3j.protocol.core.methods.response.TransactionReceipt;
import org.web3j.tx.TransactionManager;
import org.web3j.abi.TypeReference;
import org.web3j.abi.datatypes.*;
import org.web3j.abi.datatypes.generated.Uint256;

import java.math.BigInteger;

import java.util.Arrays;
import java.util.Collections;
import java.util.List;
import java.util.concurrent.Callable;

/**
 * Web3j Java wrapper for the {@code FirmwareRegistry} smart contract.
 * Package-private — only {@code BlockchainServiceImpl} uses this directly.
 *
 * In a real project this class is auto-generated by the Web3j CLI from the
 * compiled ABI + bytecode:
 *   web3j generate solidity -a FirmwareRegistry.abi -b FirmwareRegistry.bin \
 *       -o src/main/java -p com.cybersecuals.gridgarrison.trust.contract
 *
 * Solidity interface (conceptual):
 * <pre>
 * function getGoldenHash(string calldata stationId) external view returns (string memory);
 * function registerGoldenHash(string calldata stationId,
 *                              string calldata goldenHash) external;
 * </pre>
 */
public class FirmwareRegistryContract extends Contract {

    public static final String BINARY = "";

    protected FirmwareRegistryContract(String contractAddress,
                                        Web3j web3j,
                                        Credentials credentials,
                                        ContractGasProvider gasProvider) {
        super(BINARY, contractAddress, web3j, credentials, gasProvider);
    }

    // -------------------------------------------------------------------------
    // Factory
    // -------------------------------------------------------------------------

    public static FirmwareRegistryContract load(String contractAddress,
                                                 Web3j web3j,
                                                 Credentials credentials,
                                                 ContractGasProvider gasProvider) {
        return new FirmwareRegistryContract(contractAddress, web3j, credentials, gasProvider);
    }

    public static FirmwareRegistryContract load(String contractAddress,
                                                 Web3j web3j,
                                                 TransactionManager transactionManager,
                                                 ContractGasProvider gasProvider) {
        return new FirmwareRegistryContract(contractAddress, web3j, transactionManager, gasProvider);
    }

    protected FirmwareRegistryContract(String contractAddress,
                                        Web3j web3j,
                                        TransactionManager transactionManager,
                                        ContractGasProvider gasProvider) {
        super(BINARY, contractAddress, web3j, transactionManager, gasProvider);
    }

    public static RemoteCall<FirmwareRegistryContract> deploy(Web3j web3j,
                                                                Credentials credentials,
                                                                ContractGasProvider gasProvider) {
        return deployRemoteCall(FirmwareRegistryContract.class, web3j, credentials, gasProvider, BINARY, "");
    }

    public static RemoteCall<FirmwareRegistryContract> deploy(Web3j web3j,
                                                                TransactionManager transactionManager,
                                                                ContractGasProvider gasProvider) {
        return deployRemoteCall(FirmwareRegistryContract.class, web3j, transactionManager, gasProvider, BINARY, "");
    }

    @Deprecated
    public static RemoteCall<FirmwareRegistryContract> deploy(Web3j web3j,
                                                                Credentials credentials,
                                                                BigInteger gasPrice,
                                                                BigInteger gasLimit) {
        return deployRemoteCall(FirmwareRegistryContract.class, web3j, credentials, gasPrice, gasLimit, BINARY, "");
    }

    // -------------------------------------------------------------------------
    // Read functions
    // -------------------------------------------------------------------------

    /**
     * Calls {@code getGoldenHash(stationId)} — view function, no gas.
     */
    public RemoteCall<String> getGoldenHash(String stationId) {
        final Function function = new Function(
            "getGoldenHash",
            Arrays.asList(new Utf8String(stationId)),
            Collections.singletonList(new TypeReference<Utf8String>() {})
        );
        return executeRemoteCallSingleValueReturn(function, String.class);
    }

    /**
     * Calls {@code getSignedGoldenRecord(stationId)} and returns native fields.
     */
    public RemoteCall<SignedGoldenRecord> getSignedGoldenRecord(String stationId) {
        final Function function = new Function(
            "getSignedGoldenRecord",
            Arrays.asList(new Utf8String(stationId)),
            Arrays.asList(
                new TypeReference<Utf8String>() {},
                new TypeReference<Utf8String>() {},
                new TypeReference<Utf8String>() {},
                new TypeReference<Uint256>() {}
            )
        );

        return new RemoteCall<>(new Callable<>() {
            @Override
            public SignedGoldenRecord call() throws Exception {
                List<Type> values = executeCallMultipleValueReturn(function);
                return new SignedGoldenRecord(
                    values.get(0).getValue().toString(),
                    values.get(1).getValue().toString(),
                    values.get(2).getValue().toString(),
                    (BigInteger) values.get(3).getValue()
                );
            }
        });
    }

    // -------------------------------------------------------------------------
    // Write functions
    // -------------------------------------------------------------------------

    /**
     * Calls {@code registerGoldenHash(stationId, goldenHash)}.
     * Submits a signed transaction — costs gas.
     */
    public RemoteCall<TransactionReceipt> registerGoldenHash(String stationId,
                                                              String goldenHash) {
        final Function function = new Function(
            "registerGoldenHash",
            Arrays.asList(
                new Utf8String(stationId),
                new Utf8String(goldenHash)
            ),
            Collections.emptyList()
        );
        return executeRemoteCallTransaction(function);
    }

    /**
     * Calls {@code registerSignedGoldenHash(stationId, hash, signature, manufacturerId)}.
     */
    public RemoteCall<TransactionReceipt> registerSignedGoldenHash(String stationId,
                                                                   String goldenHash,
                                                                   String manufacturerSignature,
                                                                   String manufacturerId) {
        final Function function = new Function(
            "registerSignedGoldenHash",
            Arrays.asList(
                new Utf8String(stationId),
                new Utf8String(goldenHash),
                new Utf8String(manufacturerSignature),
                new Utf8String(manufacturerId)
            ),
            Collections.emptyList()
        );
        return executeRemoteCallTransaction(function);
    }

    /**
     * Calls {@code recordSessionEvent(chargerId, sessionId, state)}.
     * Emits an on-chain event for operational session activity.
     */
    public RemoteCall<TransactionReceipt> recordSessionEvent(String stationId,
                                                              String sessionId,
                                                              String state) {
        final Function function = new Function(
            "recordSessionEvent",
            Arrays.asList(
                new Utf8String(stationId),
                new Utf8String(sessionId),
                new Utf8String(state)
            ),
            Collections.emptyList()
        );
        return executeRemoteCallTransaction(function);
    }

    public record SignedGoldenRecord(String goldenHash,
                                     String manufacturerSignature,
                                     String manufacturerId,
                                     BigInteger registeredAt) {
    }
}
